   push di                 ;    1 -- 10D1:06B5 57                    [DI=0902]
   sub bx, bx              ;    1 -- 10D1:06B6 2B DB                 [BX=0000 BX=0000]
   ; DI = 0x0202: CS field of IVT entry for INT 0x80 (scan start)
   mov di, 0x0202          ;    1 -- 10D1:06B8 BF 02 02              [DI=0202]
sb_scan_loop_top:   ; 10D1:06BB
   mov es, bx              ;   64 -- 10D1:06BB 8E C3                 [ES=0000 BX=0000]
   ; read the CS (segment) of this IVT handler entry
   mov ax, [di]            ;   64 -- 10D1:06BD 26 8B 05            
   ; skip null/unset handlers
   or ax, ax               ;   64 -- 10D1:06C0 0B C0                 [AX=F000 AX=F000]
   je 0x06f0               ;   64 -- 10D1:06C2 74 2C              sb_scan_loop_next   
   ; point ES at the handler segment to probe it
   mov es, ax              ;   64 -- 10D1:06C4 8E C0                 [ES=F000 AX=F000]
